  1→<!DOCTYPE html>
  2→<html lang="en">
  3→<head>
  4→<meta charset="UTF-8">
  5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
  6→<title>Squad Stats - Skogix, ZCOPE & Brave Boy</title>
  7→<script src="https://cdn.jsdelivr.net/npm/chart.js@4.5.1" integrity="sha384-jb8JQMbMoBUzgWatfe6COACi2ljcDdZQ2OxczGA3bGNeWe+6DChMTBJemed7ZnvJ" crossorigin="anonymous"></script>
  8→<style>
  9→:root {
 10→  --bg: #0f1923; --card: #1a2332; --card-border: #243447;
 11→  --accent: #e94560; --gold: #f5a623; --green: #4ade80; --red: #f87171;
 12→  --blue: #60a5fa; --purple: #a78bfa; --cyan: #22d3ee;
 13→  --text: #e2e8f0; --text-dim: #64748b;
 14→  --str: #ef4444; --agi: #22c55e; --int: #3b82f6; --all: #eab308;
 15→  --p1: #e94560; --p2: #60a5fa; --p3: #4ade80;
 16→}
 17→* { margin:0; padding:0; box-sizing:border-box; }
 18→body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background:var(--bg); color:var(--text); }
 19→.dash { max-width:1400px; margin:0 auto; padding:20px; }
 20→
 21→/* Title */
 22→.title-bar {
 23→  text-align:center; padding:24px; margin-bottom:20px;
 24→  background:linear-gradient(135deg, #1a2332 0%, #0f3460 50%, #1a2332 100%);
 25→  border-radius:16px; border:1px solid var(--card-border);
 26→}
 27→.title-bar h1 {
 28→  font-size:32px; font-weight:900;
 29→  background:linear-gradient(135deg, var(--accent), var(--gold), var(--cyan));
 30→  -webkit-background-clip:text; -webkit-text-fill-color:transparent; background-clip:text;
 31→}
 32→.title-bar .sub { font-size:13px; color:var(--text-dim); margin-top:4px; }
 33→
 34→/* Player Cards Row */
 35→.players-row { display:grid; grid-template-columns:repeat(3, 1fr); gap:16px; margin-bottom:20px; }
 36→@media (max-width:900px) { .players-row { grid-template-columns:1fr; } }
 37→.player-card {
 38→  background:var(--card); border-radius:14px; padding:20px;
 39→  border:2px solid var(--card-border); transition:border-color 0.2s;
 40→}
 41→.player-card:nth-child(1) { border-color: color-mix(in srgb, var(--p1) 40%, transparent); }
 42→.player-card:nth-child(2) { border-color: color-mix(in srgb, var(--p2) 40%, transparent); }
 43→.player-card:nth-child(3) { border-color: color-mix(in srgb, var(--p3) 40%, transparent); }
 44→
 45→.pc-header { display:flex; align-items:center; gap:14px; margin-bottom:16px; }
 46→.pc-header img { width:56px; height:56px; border-radius:50%; border:2px solid var(--card-border); }
 47→.pc-header .pc-name { font-size:18px; font-weight:800; }
 48→.pc-header .pc-rank { font-size:11px; color:var(--gold); }
 49→.pc-header .pc-wr { font-size:12px; }
 50→
 51→.pc-stats { display:grid; grid-template-columns:repeat(3, 1fr); gap:8px; margin-bottom:14px; }
 52→.pc-stat { background:var(--bg); border-radius:8px; padding:8px; text-align:center; }
 53→.pc-stat .label { font-size:9px; text-transform:uppercase; letter-spacing:1px; color:var(--text-dim); }
 54→.pc-stat .val { font-size:18px; font-weight:800; margin-top:2px; }
 55→
 56→.pc-form { display:flex; gap:3px; flex-wrap:wrap; }
 57→.pc-form .dot { width:22px; height:22px; border-radius:5px; display:flex; align-items:center; justify-content:center; font-size:9px; font-weight:800; }
 58→.pc-form .dot.w { background:rgba(74,222,128,0.2); color:var(--green); }
 59→.pc-form .dot.l { background:rgba(248,113,113,0.2); color:var(--red); }
 60→
 61→.pc-heroes { margin-top:14px; }
 62→.pc-heroes h4 { font-size:10px; text-transform:uppercase; letter-spacing:1px; color:var(--text-dim); margin-bottom:6px; }
 63→.ph-item { display:flex; align-items:center; gap:6px; padding:3px 0; font-size:11px; }
 64→.ph-item img { width:28px; height:16px; border-radius:3px; object-fit:cover; }
 65→.ph-item .ph-wr { margin-left:auto; font-weight:700; font-size:10px; }
 66→.ph-item .ph-g { font-size:9px; color:var(--text-dim); margin-left:4px; }
 67→
 68→/* Charts */
 69→.chart-grid { display:grid; grid-template-columns:1fr 1fr; gap:16px; margin-bottom:20px; }
 70→@media (max-width:900px) { .chart-grid { grid-template-columns:1fr; } }
 71→.chart-card { background:var(--card); border:1px solid var(--card-border); border-radius:12px; padding:20px; }
 72→.chart-card h3 { font-size:12px; text-transform:uppercase; letter-spacing:1px; color:var(--text-dim); margin-bottom:14px; }
 73→.chart-full { grid-column: 1 / -1; }
 74→
 75→/* Comparison Table */
 76→.comp-section { background:var(--card); border:1px solid var(--card-border); border-radius:12px; padding:20px; margin-bottom:20px; }
 77→.comp-section h3 { font-size:12px; text-transform:uppercase; letter-spacing:1px; color:var(--text-dim); margin-bottom:14px; }
 78→table { width:100%; border-collapse:collapse; font-size:12px; }
 79→th { text-align:left; padding:8px 10px; color:var(--text-dim); font-size:10px; text-transform:uppercase; letter-spacing:1px; border-bottom:1px solid var(--card-border); }
 80→td { padding:6px 10px; border-bottom:1px solid rgba(255,255,255,0.03); }
 81→tr:hover td { background:rgba(255,255,255,0.02); }
 82→.hero-cell { display:flex; align-items:center; gap:6px; }
 83→.hero-cell img { width:28px; height:16px; border-radius:3px; object-fit:cover; }
 84→
 85→/* Player color dots */
 86→.pdot { display:inline-block; width:8px; height:8px; border-radius:50%; margin-right:4px; }
 87→.pdot.p1 { background:var(--p1); } .pdot.p2 { background:var(--p2); } .pdot.p3 { background:var(--p3); }
 88→
 89→.footer { text-align:center; padding:20px; font-size:11px; color:var(--text-dim); }
 90→.footer a { color:var(--accent); }
 91→</style>
 92→</head>
 93→<body>
 94→<div class="dash">
 95→
 96→<div class="title-bar">
 97→  <h1>The Squad</h1>
 98→  <div class="sub">Skogix + ZCOPE + Brave Boy &mdash; Dota 2 Team Stats</div>
 99→</div>
100→
101→<div class="players-row" id="players-row"></div>
102→
103→<div class="chart-grid">
104→  <div class="chart-card">
105→    <h3>Win Rate Comparison</h3>
106→    <canvas id="chart-wr-comp"></canvas>
107→  </div>
108→  <div class="chart-card">
