122→    <canvas id="chart-sig"></canvas>
123→  </div>
124→</div>
125→
126→<!-- Shared Hero Pool -->
127→<div class="comp-section">
128→  <h3>Overlapping Hero Pools (heroes 2+ squad members play)</h3>
129→  <div style="overflow-x:auto">
130→    <table id="overlap-table">
131→      <thead>
132→        <tr>
133→          <th>Hero</th>
134→          <th><span class="pdot p1"></span>Skogix</th>
135→          <th><span class="pdot p2"></span>ZCOPE</th>
136→          <th><span class="pdot p3"></span>Brave Boy</th>
137→        </tr>
138→      </thead>
139→      <tbody id="overlap-tbody"></tbody>
140→    </table>
141→  </div>
142→</div>
143→
144→<!-- Recent Matches Side by Side -->
145→<div class="comp-section">
146→  <h3>Recent Matches (Last 10 Each)</h3>
147→  <div style="overflow-x:auto">
148→    <table>
149→      <thead><tr>
150→        <th colspan="4" style="color:var(--p1)">Skogix</th>
151→        <th colspan="4" style="color:var(--p2)">ZCOPE</th>
152→        <th colspan="4" style="color:var(--p3)">Brave Boy</th>
153→      </tr><tr>
154→        <th>Hero</th><th>K/D/A</th><th>R</th><th>GPM</th>
155→        <th>Hero</th><th>K/D/A</th><th>R</th><th>GPM</th>
156→        <th>Hero</th><th>K/D/A</th><th>R</th><th>GPM</th>
157→      </tr></thead>
158→      <tbody id="recent-tbody"></tbody>
159→    </table>
160→  </div>
161→</div>
162→
163→<div class="footer">
164→  Data from <a href="https://opendota.com">OpenDota</a> &mdash; Generated Feb 2026
165→</div>
166→</div>
