function buildCharts() {
  Chart.defaults.color = '#64748b';
  Chart.defaults.borderColor = 'rgba(255,255,255,0.05)';

  // WR comparison
  var names = P.map(function(p){return p.name;});
  new Chart(document.getElementById('chart-wr-comp'), {
    type: 'bar',
    data: {
      labels: names,
      datasets: [{
        label: 'Win Rate %',
        data: P.map(function(p){ var t=p.wl.win+p.wl.lose; return t>0 ? Math.round(p.wl.win/t*1000)/10 : 0; }),
        backgroundColor: PCOLORS_A,
        borderRadius: 6
      }]
    },
    options: { responsive:true, plugins:{legend:{display:false}}, scales:{y:{min:40,max:55,ticks:{callback:function(v){return v+'%';}}}} }
  });

  // Stats radar-style comparison (bar grouped)
  new Chart(document.getElementById('chart-stats-comp'), {
    type: 'bar',
    data: {
      labels: ['Kills', 'Deaths', 'Assists', 'Last Hits'],
      datasets: P.map(function(p, i) {
        return {
          label: p.name,
          data: [p.totals.kills||0, p.totals.deaths||0, p.totals.assists||0, Math.round((p.totals.last_hits||0)/10)],
          backgroundColor: PCOLORS_A[i],
          borderRadius: 4
        };
      })
    },
    options: { responsive:true, plugins:{legend:{position:'top'},tooltip:{callbacks:{label:function(ctx){
      if (ctx.dataIndex === 3) return ctx.dataset.label + ': ' + (ctx.raw * 10) + ' LH';
      return ctx.dataset.label + ': ' + ctx.raw;
    }}}}}
  });

  // Role coverage
  var allRoles = {};
  P.forEach(function(p) {
    Object.keys(p.roles).forEach(function(r) { allRoles[r] = true; });
  });
  var roleLabels = Object.keys(allRoles).sort(function(a, b) {
    var sumA = P.reduce(function(s,p){return s+(p.roles[a]?p.roles[a].g:0);},0);
    var sumB = P.reduce(function(s,p){return s+(p.roles[b]?p.roles[b].g:0);},0);
    return sumB - sumA;
  }).slice(0, 8);

  new Chart(document.getElementById('chart-roles'), {
    type: 'bar',
    data: {
      labels: roleLabels,
      datasets: P.map(function(p, i) {
        return {
          label: p.name,
          data: roleLabels.map(function(r) { return p.roles[r] ? p.roles[r].g : 0; }),
          backgroundColor: PCOLORS_A[i],
          borderRadius: 4
        };
      })
    },
    options: { responsive:true, plugins:{legend:{position:'top'}}, scales:{x:{},y:{}} }
  });

  // Economy comparison
  new Chart(document.getElementById('chart-econ'), {
    type: 'bar',
    data: {
      labels: names,
      datasets: [{
        label: 'GPM', data: P.map(function(p){return Math.round(p.totals.gold_per_min||0);}),
        backgroundColor: 'rgba(245,166,35,0.7)', borderRadius: 4
      }, {
        label: 'XPM', data: P.map(function(p){return Math.round(p.totals.xp_per_min||0);}),
        backgroundColor: 'rgba(96,165,250,0.7)', borderRadius: 4
      }]
    },
    options: { responsive:true, plugins:{legend:{position:'top'}} }
  });

  // Signature heroes
  var allHeroes = [];
  P.forEach(function(p, i) {
    p.heroStats.slice(0, 5).forEach(function(h) {
      allHeroes.push({name: h.name, games: h.g, player: p.name, pIdx: i, wr: h.wr});
    });
  });
  allHeroes.sort(function(a,b){return b.games - a.games;});
  var top12 = allHeroes.slice(0, 12);

  new Chart(document.getElementById('chart-sig'), {
    type: 'bar',
    data: {
      labels: top12.map(function(h){return h.name + ' (' + h.player.split(' ')[0] + ')';}),
      datasets: [{
        label: 'Games',
        data: top12.map(function(h){return h.games;}),
        backgroundColor: top12.map(function(h){return PCOLORS_A[h.pIdx];}),
        borderRadius: 4
      }]
    },
    options: { indexAxis:'y', responsive:true, plugins:{legend:{display:false}} }
  });
}

function buildOverlapTable() {
  // Find heroes that 2+ players play (10+ games)
  var heroPlayers = {};
  P.forEach(function(p, i) {
    p.heroStats.forEach(function(h) {
      if (h.g >= 10) {
        if (!heroPlayers[h.name]) heroPlayers[h.name] = [{},{},{}];
        heroPlayers[h.name][i] = h;
      }
    });
  });

  var overlaps = [];
  Object.keys(heroPlayers).forEach(function(name) {
    var count = heroPlayers[name].filter(function(p){return p && p.g;}).length;
    if (count >= 2) overlaps.push({name: name, data: heroPlayers[name]});
  });
  overlaps.sort(function(a,b) {
    var ta = a.data.reduce(function(s,d){return s+(d&&d.g?d.g:0);},0);
    var tb = b.data.reduce(function(s,d){return s+(d&&d.g?d.g:0);},0);
    return tb - ta;
  });

  var tbody = document.getElementById('overlap-tbody');
  var html = '';
  overlaps.forEach(function(o) {
    html += '<tr>';
    var anyImg = o.data.find(function(d){return d && d.img;});
    html += '<td><div class="hero-cell">' + (anyImg ? '<img src="'+anyImg.img+'">' : '') + o.name + '</div></td>';
    o.data.forEach(function(d) {
      if (d && d.g) {
        var wrC = d.wr >= 55 ? 'var(--green)' : d.wr < 45 ? 'var(--red)' : 'var(--text)';
        html += '<td><span style="color:'+wrC+';font-weight:700">' + d.wr + '%</span> <span style="color:var(--text-dim);font-size:10px">(' + d.g + 'g)</span></td>';
      } else {
        html += '<td style="color:var(--text-dim)">-</td>';
      }
    });
    html += '</tr>';
  });
  tbody.innerHTML = html;
}

function buildRecentTable() {
  var tbody = document.getElementById('recent-tbody');
  var html = '';
  for (var i = 0; i < 10; i++) {
    html += '<tr>';
    P.forEach(function(p) {
      var m = p.recent[i];
      if (m) {
        var rc = m.result === 'Win' ? 'var(--green)' : 'var(--red)';
        html += '<td><div class="hero-cell"><img src="'+m.img+'">'+m.hero+'</div></td>';
        html += '<td>'+m.k+'/'+m.d+'/'+m.a+'</td>';
        html += '<td style="color:'+rc+';font-weight:700">'+m.result[0]+'</td>';
        html += '<td style="color:var(--gold)">'+m.gpm+'</td>';
      } else {
        html += '<td colspan="4">-</td>';
      }
    });
    html += '</tr>';
  }
  tbody.innerHTML = html;
}

init();
</script>
</body>
</html>

