    html += '<div class="pc-stat"><div class="label">GPM</div><div class="val" style="color:var(--gold)">' + Math.round(p.totals.gold_per_min) + '</div></div>';
    html += '<div class="pc-stat"><div class="label">XPM</div><div class="val" style="color:var(--cyan)">' + Math.round(p.totals.xp_per_min) + '</div></div>';
    html += '<div class="pc-stat"><div class="label">APM</div><div class="val" style="color:var(--purple)">' + Math.round(p.totals.actions_per_min) + '</div></div>';
    html += '</div>';

    // Form
    html += '<div class="pc-form-section">';
    html += '<div class="pc-form-header"><span class="form-title">Last 20</span>';
    html += '<span class="form-record" style="color:var(--text)">' + fw + 'W ' + (20-fw) + 'L</span></div>';
    html += '<div class="pc-form-dots">';
    p.form.forEach(function(w) { html += '<div class="form-dot ' + (w ? 'w' : 'l') + '">' + (w ? 'W' : 'L') + '</div>'; });
    html += '</div></div>';

    // Sparkline
    html += '<div class="pc-sparkline"><canvas id="spark-' + i + '" height="36"></canvas></div>';

    // Top heroes
    html += '<div class="pc-heroes"><h4>Signature Heroes</h4>';
    p.heroStats.slice(0, 5).forEach(function(h) {
      var wrC = h.wr >= 55 ? 'var(--green)' : h.wr < 45 ? 'var(--red)' : 'var(--text)';
      var barPct = Math.round(h.g / maxGames * 100);
      html += '<div class="hero-row">';
      html += '<img src="' + h.img + '" alt="' + h.name + '">';
      html += '<span class="hero-name">' + h.name + '</span>';
      html += '<span class="hero-bar-wrap"><span class="hero-bar" style="width:' + barPct + '%;background:' + PCOLORS[i] + '"></span></span>';
      html += '<span class="hero-wr" style="color:' + wrC + '">' + h.wr + '%</span>';
      html += '<span class="hero-games">' + h.g + '</span>';
      html += '</div>';
    });
    html += '</div></div>';
  });
  grid.innerHTML = html;

  // Draw sparklines
  P.forEach(function(p, i) { drawSparkline('spark-' + i, p.form, PCOLORS[i]); });
}

function drawSparkline(canvasId, form, color) {
  var canvas = document.getElementById(canvasId);
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  canvas.width = canvas.offsetWidth * 2;
  canvas.height = 72;
  ctx.scale(1, 1);
  // Calculate rolling WR (cumulative)
  var points = [];
  var wins = 0;
  for (var j = form.length - 1; j >= 0; j--) {
    wins += form[j];
    points.push(wins / (form.length - j) * 100);

